SELECT total_earnings, total_articles
FROM writer_stats
WHERE writer_id = 1;

SELECT COUNT(writer_id) AS active_writers_count, AVG(hourly_rate) AS average_hourly_rate
FROM writers
WHERE status = 'active';

SELECT writer_name, location, preferred_categories
FROM writers
ORDER BY writer_name ASC;

SELECT SUM(earnings_amount) AS total_earnings
FROM writer_earnings
WHERE writer_id = 1;
